import json
with open('dana_benchmark.ipynb') as f:
    nb = json.load(f)
cells = nb['cells']

# Fix the renumbering: undo the damage and renumber correctly
renumber = [
    ('## 11. Aggregate', '## 19. Aggregate'),
    ('## 12. Statistical', '## 20. Statistical'),
    ('## 13. Visualization', '## 21. Visualization'),
    ('## 14. Export', '## 22. Export'),
]

for cell in cells:
    if cell.get('cell_type') == 'markdown':
        # First deduplicate (the bug created 4x lines)
        # Find unique lines while preserving order
        seen = set()
        deduped = []
        for line in cell['source']:
            if line not in seen:
                seen.add(line)
                deduped.append(line)
        # Apply renumbering
        for i, line in enumerate(deduped):
            for old, new in renumber:
                if old in line:
                    deduped[i] = line.replace(old, new)
        cell['source'] = deduped

with open('dana_benchmark.ipynb', 'w') as f:
    json.dump(nb, f, indent=2, ensure_ascii=False)

# Verify
for i, c in enumerate(cells):
    if c.get('cell_type') == 'markdown':
        src = ''.join(c['source'])
        if '##' in src:
            for line in c['source']:
                s = line.strip()
                if s.startswith('##'):
                    print(f'[{i:2d}] {s[:60]}')
                    break
print(f'Total cells: {len(cells)}')
"
